import React, { useEffect, useMemo, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Sun, Moon, Laptop, LogOut, Menu, User2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuLabel,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetTrigger } from "@/components/ui/sheet";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";

/**
 * Ultra-modern, responsive, and accessible Navbar
 * - TailwindCSS for styling
 * - shadcn/ui for polished components
 * - lucide-react icons
 * - framer-motion micro-animations
 * - Light / Dark / System theme with localStorage persistence (key: "tema")
 * - Reads current user from localStorage key "kullanici" (expects { kullanici: string })
 */

const THEME_KEY = "tema"; // "light" | "dark" | "system"

function readUserName() {
    try {
        const raw = localStorage.getItem("kullanici");
        if (!raw) return "";
        const parsed = JSON.parse(raw);
        return parsed?.kullanici || "";
    } catch {
        return "";
    }
}

function getSystemPrefersDark() {
    if (typeof window === "undefined") return false;
    return window.matchMedia && window.matchMedia("(prefers-color-scheme: dark)").matches;
}

function resolveActiveTheme(storedTheme) {
    if (storedTheme === "system") {
        return getSystemPrefersDark() ? "dark" : "light";
    }
    return storedTheme || (getSystemPrefersDark() ? "dark" : "light");
}

function applyTheme(theme) {
    if (typeof document === "undefined") return;
    const html = document.documentElement;
    const effective = resolveActiveTheme(theme);
    // Tailwind dark mode support
    if (effective === "dark") {
        html.classList.add("dark");
    } else {
        html.classList.remove("dark");
    }
    // Also expose as data attribute for any CSS Variable themes you might have
    html.setAttribute("data-theme", effective);
}

export default function Navbar() {
    const [kullaniciIsmi, setKullaniciIsmi] = useState("");
    const [themePref, setThemePref] = useState(() => {
        if (typeof window === "undefined") return "dark";
        return localStorage.getItem(THEME_KEY) || "system"; // default to system for modern UX
    });

    const activeTheme = useMemo(() => resolveActiveTheme(themePref), [themePref]);

    useEffect(() => {
        setKullaniciIsmi(readUserName());
    }, []);

    useEffect(() => {
        // Persist preference & apply
        try {
            localStorage.setItem(THEME_KEY, themePref);
        } catch { }
        applyTheme(themePref);

        // Live-update when system theme changes and preference === system
        if (themePref === "system" && typeof window !== "undefined") {
            const mq = window.matchMedia("(prefers-color-scheme: dark)");
            const handler = () => applyTheme("system");
            mq.addEventListener?.("change", handler);
            mq.addListener?.(handler); // legacy Safari
            return () => {
                mq.removeEventListener?.("change", handler);
                mq.removeListener?.(handler);
            };
        }
    }, [themePref]);

    const initials = useMemo(() => {
        if (!kullaniciIsmi) return "?";
        return kullaniciIsmi
            .split(/\s+/)
            .map((p) => p[0])
            .join("")
            .slice(0, 2)
            .toUpperCase();
    }, [kullaniciIsmi]);

    const handleLogout = () => {
        try {
            localStorage.removeItem("kullanici");
        } catch { }
        window.location.reload();
    };

    const ThemeIcon = () => (
        <AnimatePresence mode="wait" initial={false}>
            {activeTheme === "dark" ? (
                <motion.span
                    key="moon"
                    initial={{ rotate: -90, opacity: 0 }}
                    animate={{ rotate: 0, opacity: 1 }}
                    exit={{ rotate: 90, opacity: 0 }}
                    transition={{ type: "spring", stiffness: 300, damping: 20 }}
                    aria-hidden
                    className="inline-flex"
                >
                    <Moon className="h-4 w-4" />
                </motion.span>
            ) : (
                <motion.span
                    key="sun"
                    initial={{ rotate: 90, opacity: 0 }}
                    animate={{ rotate: 0, opacity: 1 }}
                    exit={{ rotate: -90, opacity: 0 }}
                    transition={{ type: "spring", stiffness: 300, damping: 20 }}
                    aria-hidden
                    className="inline-flex"
                >
                    <Sun className="h-4 w-4" />
                </motion.span>
            )}
        </AnimatePresence>
    );

    const ThemeLabel = () => (
        <span className="ml-2 text-xs font-medium opacity-80 hidden sm:inline">
            {themePref === "system" ? "Sistem" : activeTheme === "dark" ? "Koyu" : "Açık"}
        </span>
    );

    const Brand = () => (
        <div className="flex items-center gap-2">
            <div className="h-8 w-8 rounded-2xl bg-gradient-to-br from-indigo-500 to-purple-500 shadow-md" />
            <span className="text-base sm:text-lg font-semibold tracking-tight">Uygulama</span>
        </div>
    );

    return (
        <header className="sticky top-0 z-50 w-full border-b bg-background/80 backdrop-blur supports-[backdrop-filter]:bg-background/60">
            <nav className="mx-auto flex h-14 max-w-7xl items-center justify-between px-3 sm:px-4">
                {/* Left: Brand (collapses on mobile into sheet) */}
                <div className="flex items-center gap-2">
                    <div className="md:hidden">
                        <Sheet>
                            <SheetTrigger asChild>
                                <Button variant="ghost" size="icon" aria-label="Menüyü aç">
                                    <Menu className="h-5 w-5" />
                                </Button>
                            </SheetTrigger>
                            <SheetContent side="left" className="w-80">
                                <SheetHeader>
                                    <SheetTitle className="inline-flex items-center gap-2">
                                        <Brand />
                                    </SheetTitle>
                                </SheetHeader>
                                <div className="mt-6 grid gap-2">
                                    {/* Place navigational links here if needed */}
                                    <Button variant="ghost" className="justify-start">
                                        Ana Sayfa
                                    </Button>
                                    <Button variant="ghost" className="justify-start">
                                        Özellikler
                                    </Button>
                                    <Button variant="ghost" className="justify-start">
                                        Hakkında
                                    </Button>
                                </div>
                            </SheetContent>
                        </Sheet>
                    </div>
                    <div className="hidden md:block">
                        <Brand />
                    </div>
                </div>

                {/* Right: User + Theme + Logout */}
                <div className="flex items-center gap-1 sm:gap-2">
                    {/* Theme Picker */}
                    <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                            <Button variant="ghost" className="px-2 sm:px-3" aria-label="Tema değiştir">
                                <ThemeIcon />
                                <ThemeLabel />
                            </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end" className="w-44">
                            <DropdownMenuLabel>Tema</DropdownMenuLabel>
                            <DropdownMenuSeparator />
                            <DropdownMenuItem onClick={() => setThemePref("light")}>
                                <Sun className="mr-2 h-4 w-4" /> Açık
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={() => setThemePref("dark")}>
                                <Moon className="mr-2 h-4 w-4" /> Koyu
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={() => setThemePref("system")}>
                                <Laptop className="mr-2 h-4 w-4" /> Sistem
                            </DropdownMenuItem>
                        </DropdownMenuContent>
                    </DropdownMenu>

                    {/* User box */}
                    <div className="flex items-center gap-2 rounded-xl border px-2 py-1">
                        <Avatar className="h-7 w-7">
                            <AvatarFallback>
                                {initials || <User2 className="h-4 w-4" />}
                            </AvatarFallback>
                        </Avatar>
                        <span className="max-w-[10rem] truncate text-sm font-medium opacity-90 hidden sm:inline">
                            {kullaniciIsmi || "Misafir"}
                        </span>
                    </div>

                    {/* Logout */}
                    <Button onClick={handleLogout} variant="secondary" className="ml-1">
                        <LogOut className="mr-2 h-4 w-4" />
                        <span className="hidden sm:inline">Çıkış</span>
                    </Button>
                </div>
            </nav>
        </header>
    );
}
